children.text:
@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/Jubily/test/layout/data/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

body { writing-mode: vertical-rl; }
.container {
  position: relative;
  background: green;
  color: green;
  font: 16px/1 Ahem;
  border: solid black 3px;
  height: 400px;
  margin: 0 16px;
  padding: 2px;
}
.red { color: red; }
.cb {
  position: relative;
  inset-block-start: 2px;
  inset-inline-start: 2px;
}
.rtl { direction: rtl; }
.ltr { direction: ltr; }
.inline { display: inline; }
.abs { position: absolute; }

.indent { text-indent: 20px; }
* { text-indent: initial; }
